// app/utils/HtmlSanitizer.scala
package utils

import org.owasp.html.PolicyFactory
import org.owasp.html.Sanitizers
import org.owasp.html.HtmlPolicyBuilder

object HtmlSanitizer {

  val policy: PolicyFactory = new HtmlPolicyBuilder()
    .allowElements("b", "i", "u", "em", "strong", "a", "p", "br", "ul", "ol", "li",
      "h1", "h2", "h3", "h4", "h5", "h6", "blockquote", "pre", "code", "img", "hr")
    .allowAttributes("href").onElements("a")
    .allowAttributes("src", "alt", "title", "width", "height").onElements("img")
    .allowAttributes("class").globally()
    .allowUrlProtocols("http", "https", "mailto")
    .requireRelNofollowOnLinks()
    .toFactory()

  def sanitize(untrustedHtml: String): String = {
    policy.sanitize(untrustedHtml)
  }
}